import{c as s,S as t,j as a,m as i}from"./chunks/framework.HqPCP1nz.js";const u=JSON.parse('{"title":"Contributing","description":"","frontmatter":{},"headers":[],"relativePath":"contributing.md","filePath":"contributing.md","lastUpdated":null}'),o={name:"contributing.md"};function n(d,e,l,r,c,p){return t(),a("div",null,[...e[0]||(e[0]=[i(`<h1 id="Contributing" tabindex="-1">Contributing <a class="header-anchor" href="#Contributing" aria-label="Permalink to &quot;Contributing {#Contributing}&quot;">​</a></h1><p>Issues and pull requests are welcome at <a href="https://github.com/epiforecasts/BVDOutbreakSize" target="_blank" rel="noreferrer">epiforecasts/BVDOutbreakSize</a>. This page covers how the project is laid out, how to run it, and the conventions to follow when changing it.</p><h2 id="Repository-layout" tabindex="-1">Repository layout <a class="header-anchor" href="#Repository-layout" aria-label="Permalink to &quot;Repository layout {#Repository-layout}&quot;">​</a></h2><ul><li><p><code>src/BVDOutbreakSize.jl</code> — the package: data loading (<code>load_observations</code>), NUTS sampling (<code>nuts_sample</code>), the shared Gauss-Legendre integrators (<code>integrate</code>, <code>expected_deaths</code>, <code>integrate_cumulative</code>, <code>integrate_exports_deaths</code>), summary and comparison tables, plotting, the no-onward-deaths projection (<code>predict_no_onward_deaths</code>) and forecast helpers (<code>forecast_reported</code>). The published Imperial point estimates live here as <code>REPORT_SCENARIOS</code>.</p></li><li><p><code>docs/examples/analysis.jl</code> — the Literate walkthrough that is the analysis. It defines the Turing submodels and composers, runs the fits, and writes every output. This is the main artifact.</p></li><li><p><code>docs/make.jl</code> — DocumenterVitepress build. Copies <code>README.md</code> to <code>index.md</code>, executes the literate to <code>analysis.md</code>, and builds the bibliography.</p></li><li><p><code>data/observations.toml</code> — single source of truth for observation data (case and death counts, traveller volumes, sources). Loaded via <code>load_observations()</code> and never hardcoded. Update this one file for a new situation report and the analysis picks it up. The literate re-binds its observation <code>const</code>s from the loaded TOML, so the package constants are defaults only.</p></li><li><p><code>scripts/run.jl</code> — regenerates published results by including the literate and writes CSVs to <code>output/</code>.</p></li><li><p><code>test/</code> — one file per feature, driven by <code>test/runtests.jl</code>.</p></li><li><p><code>external/bdbv-linelist-analysis</code> — git submodule, source of the onset-to-death delay priors.</p></li></ul><h2 id="Running-and-testing" tabindex="-1">Running and testing <a class="header-anchor" href="#Running-and-testing" aria-label="Permalink to &quot;Running and testing {#Running-and-testing}&quot;">​</a></h2><p>There is no Taskfile. Use the <code>julia --project</code> commands:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Instantiate the package environment</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.instantiate()&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run the analysis</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/examples/analysis.jl</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Regenerate the published output CSVs into output/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/run.jl</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Run the full test suite</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=.</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; Pkg.test()&#39;</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Build the docs (executes the literate, HTML in docs/build/)</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -e</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;using Pkg; \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  Pkg.develop(PackageSpec(path=pwd())); Pkg.instantiate()&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">julia</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --project=docs</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> docs/make.jl</span></span></code></pre></div><p><code>test/runtests.jl</code> includes each <code>test/test_*.jl</code>. To iterate on one file, run it inside a REPL after <code>using BVDOutbreakSize</code>, or temporarily comment out the others in <code>runtests.jl</code>.</p><p>CI runs the test suite (<code>.github/workflows/test.yml</code>) and builds the docs, publishing <code>output/</code> as a GitHub Release on each push to <code>main</code> (<code>.github/workflows/docs.yml</code>).</p><h2 id="Model-architecture" tabindex="-1">Model architecture <a class="header-anchor" href="#Model-architecture" aria-label="Permalink to &quot;Model architecture {#Model-architecture}&quot;">​</a></h2><p>The model is assembled from small, swappable Turing submodels rather than one monolithic block (the build-up is drawn as a flowchart on the <a href="./analysis">Analysis</a> page). There are three layers.</p><p><strong>Building-block submodels</strong>, one per parameter family, each owning its own priors:</p><ul><li><p><code>exponential_growth_model</code> samples the doubling time <code>τ</code> and the doubling-time multiplier <code>m = T/τ</code>, not <code>τ</code> and <code>T</code> directly, to break the <code>C(T) = exp(rT)</code> ridge.</p></li><li><p><code>delay_model</code> is the gamma onset-to-death delay.</p></li><li><p><code>cfr_model</code> is the case-fatality ratio.</p></li><li><p><code>detection_window_model</code> is the export detection window <code>w</code>.</p></li><li><p><code>surveillance_dispersion_model</code> samples on the <code>1/√k</code> scale.</p></li><li><p><code>pooled_ascertainment_model</code> partially pools the DRC and Uganda reporting fractions <code>p_drc</code> and <code>p_uganda</code> on the logit scale.</p></li></ul><p><strong>Observation submodels</strong>, one per data stream, each taking the growth state, adding its forward integral and likelihood: <code>exports_model</code> (Poisson), <code>deaths_model</code> (NegBinomial), <code>cases_model</code> (NegBinomial), and <code>exports_deaths_model</code> (Poisson).</p><p><strong>Composers</strong> stitch the blocks into full generative models: <code>exports_only_model</code>, <code>deaths_only_model</code>, <code>cases_only_model</code>, <code>exports_deaths_only_model</code>, <code>imperial_only_model</code> (exports and deaths, the Imperial joint configuration), and <code>bvd_joint</code> (all four streams). Each composer conditionally includes only the likelihoods for the streams it carries. A single-stream composer never instantiates the other observation submodels, so a discrete stream is never left sampled, which would trip Turing&#39;s model check. Pass a stream as <code>missing</code> to drop its likelihood; <code>bvd_joint</code> with all streams missing is the generator used for the prior and posterior predictive checks.</p><h2 id="Conventions" tabindex="-1">Conventions <a class="header-anchor" href="#Conventions" aria-label="Permalink to &quot;Conventions {#Conventions}&quot;">​</a></h2><ul><li><p>Maximum 80 characters per line of code.</p></li><li><p>One sentence per line in prose and markdown; do not wrap prose at 80 characters.</p></li><li><p>The abstract is single-sourced in <code>README.md</code>, wrapped in <code>&lt;!-- ABSTRACT:START --&gt;</code> / <code>&lt;!-- ABSTRACT:END --&gt;</code> markers. Edit the abstract in <code>README.md</code> only. <code>docs/examples/analysis.jl</code> loads it at build time via a Documenter <code>@eval</code> block that reads <code>README.md</code> and regex-extracts the text between those markers, so do not duplicate it into the analysis page.</p></li><li><p>Table-construction and other setup code in <code>analysis.jl</code> is hidden inside <code>&lt;details&gt;</code> dropdowns via <code>#md # @raw html</code> blocks; the bare result object follows (with <code>#hide</code>) so only the output renders.</p></li><li><p>The surveillance dispersion prior is a half-normal <code>truncated(Normal(0, 1); lower = 0)</code> on <code>inv_sqrt_k</code>.</p></li><li><p>Docstrings use DocStringExtensions (<code>$(TYPEDSIGNATURES)</code>).</p></li><li><p>The AD backend is Mooncake reverse-mode; integrals use Gauss-Legendre quadrature (<code>DEATH_INTEGRAL_ALG</code> with <code>n = 64</code>, <code>CUMULATIVE_INTEGRAL_ALG</code> with <code>n = 32</code>); models compose via <code>~ to_submodel(...)</code>. The deaths-among-exports CDF is written as an inner integral of the density because the reverse-mode AD backend does not support the gamma CDF shape-parameter derivative.</p></li><li><p>NaN and Inf safe clamps (<code>safe_nbinomial</code>, <code>eps</code>-flooring of expected counts) guard against extreme NUTS warmup proposals; keep them when editing the likelihoods.</p></li></ul><h2 id="Pull-requests" tabindex="-1">Pull requests <a class="header-anchor" href="#Pull-requests" aria-label="Permalink to &quot;Pull requests {#Pull-requests}&quot;">​</a></h2><ul><li><p><code>main</code> is branch-protected; changes go through pull requests.</p></li><li><p>Run the test suite before opening a pull request.</p></li><li><p>Add a bullet to the <a href="./news">News</a> page under <code>Unreleased</code> for any user-visible change.</p></li></ul>`,19)])])}const g=s(o,[["render",n]]);export{u as __pageData,g as default};
